<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mlflow.log_param(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dataset&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;iris&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
